    68→    68→export async function questsRoutes(server: FastifyInstance) {
    69→    69→    // List Quests
    70→    70→    server.get(
    71→    71→        '/',
    72→    72→        {
    73→    73→            schema: {
    74→    74→                tags: ['Quests'],
    75→    75→                summary: 'List available quests',
    76→    76→                querystring: z.object({
    77→    77→                    status: z.nativeEnum(QUEST_STATUS).optional(),
    78→    78→                    type: z.nativeEnum(QUEST_TYPE).optional(),
    79→    79→                    limit: z.coerce.number().int().min(1).max(100).default(50),
    80→    80→                    offset: z.coerce.number().int().min(0).default(0),
    81→    81→                }),
    82→    82→                response: {
    83→    83→                    200: z.array(QuestSchema),
    84→    84→                },
    85→    85→            },
    86→    86→        },
    87→    87→        async (request) => {
    88→    88→            const { status, type, limit, offset } = request.query as any;
    89→    89→
    90→    90→            const where: any = {};
    91→    91→            if (status) where.status = status;
    92→    92→            else where.status = { not: 'draft' }; // As default, don't show drafts publicly
    93→    93→
    94→    94→            if (type) where.type = type;
    95→    95→
    96→    96→            const quests = await server.prisma.quest.findMany({
    97→    97→                where,
    98→    98→                orderBy: { createdAt: 'desc' },
    99→    99→                take: limit,
   100→   100→                skip: offset,
   101→   101→                include: {
   102→   102→                    _count: { select: { participations: true } },
   103→   103→                    participations: {
   104→   104→                        take: 5,
   105→   105→                        select: {
   106→   106→                            user: { select: USER_IDENTITY_SELECT },
   107→   107→                            agent: { select: { agentname: true } },
   108→   108→                        },
   109→   109→                        orderBy: { joinedAt: 'asc' },
   110→   110→                    },
   111→   111→                },
   112→   112→            });
   113→   113→
   114→   114→            return quests.map(({ _count, participations, ...q }) =>
   115→   115→                formatQuestResponse(q, participations, _count.participations)
   116→   116→            );
   117→   117→        }
   118→   118→    );
   119→   119→
   120→   120→    // Get Quest Details — supports token-based draft preview
   121→   121→    server.get(
   122→   122→        '/:id',
   123→   123→        {
   124→   124→            schema: {
   125→   125→                tags: ['Quests'],
   126→   126→                summary: 'Get quest details (supports draft preview via token)',
   127→   127→                params: z.object({ id: z.string().uuid() }),
   128→   128→                querystring: z.object({
   129→   129→                    token: z.string().optional(),
   130→   130→                }).optional(),
   131→   131→                response: {
   132→   132→                    200: QuestSchema.extend({
   133→   133→                        isPreview: z.boolean().optional(),
   134→   134→                        isCreator: z.boolean().optional(),
   135→   135→                        isSponsor: z.boolean().optional(),
   136→   136→                        fundingRequired: z.boolean().optional(),
   137→   137→                        previewToken: z.string().optional(),
   138→   138→                        fundUrl: z.string().optional(),
   139→   139→                        creatorUserId: z.string().nullable().optional(),
   140→   140→                        fundingMethod: z.string().nullable().optional(),
   141→   141→                        myParticipation: z.object({
   142→   142→                            id: z.string(),
   143→   143→                            status: z.string(),
   144→   144→                            payoutWallet: z.string().nullable(),
   145→   145→                            payoutStatus: z.string().nullable(),
   146→   146→                            payoutAmount: z.number().nullable(),
   147→   147→                            payoutTxHash: z.string().nullable(),
   148→   148→                            tasksCompleted: z.number().optional(),
   149→   149→                            tasksTotal: z.number().optional(),
   150→   150→                            proof: z.any().optional(),
   151→   151→                            llmRewardApiKey: z.string().nullable().optional(),
   152→   152→                            llmRewardIssuedAt: z.string().datetime().nullable().optional(),
   153→   153→                            payoutTokenApiKey: z.string().nullable().optional(),
   154→   154→                            payoutTokenStatus: z.string().nullable().optional(),
   155→   155→                            payoutTokenExpiresAt: z.string().datetime().nullable().optional(),
   156→   156→                        }).optional(),
   157→   157→                    }),
   158→   158→                },
   159→   159→            },
   160→   160→        },
   161→   161→        async (request, reply) => {
   162→   162→            const { id } = request.params as any;
   163→   163→            const { token } = (request.query as any) ?? {};
   164→   164→
   165→   165→            const quest = await server.prisma.quest.findUnique({
   166→   166→                where: { id },
   167→   167→                include: {
   168→   168→                    _count: { select: { participations: true } },
   169→   169→                    participations: {
   170→   170→                        take: 5,
   171→   171→                        include: {
   172→   172→                            user: { select: USER_IDENTITY_SELECT },
   173→   173→                            agent: { select: { agentname: true } },
   174→   174→                        },
   175→   175→                        orderBy: { joinedAt: 'asc' },
   176→   176→                    },
   177→   177→                },
   178→   178→            });
   179→   179→
   180→   180→            if (!quest) {
   181→   181→                return reply.status(404).send({ message: 'Quest not found', code: 'NOT_FOUND' } as any);
   182→   182→            }
   183→   183→
   184→   184→            // Auto-check and reset Stripe session if canceled/expired (background, non-blocking)
   185→   185→            if (quest.fundingStatus === 'pending' && quest.stripeSessionId && quest.fundingMethod === 'stripe') {
   186→   186→                // Check session status asynchronously (don't block response)
   187→   187→                (async () => {
   188→   188→                    try {
   189→   189→                        const { stripe, isStripeConfigured } = await import('../stripe/stripe.config');
   190→   190→                        if (!isStripeConfigured() || !stripe) return;
   191→   191→
   192→   192→                        const session = await stripe.checkout.sessions.retrieve(quest.stripeSessionId!);
   193→   193→
   194→   194→                        // If session is not paid, reset funding status
   195→   195→                        if (session.payment_status !== 'paid') {
   196→   196→                            const currentQuest = await server.prisma.quest.findUnique({
   197→   197→                                where: { id },
   198→   198→                                select: { fundingStatus: true },
   199→   199→                            });
   200→   200→
   201→   201→                            // Only reset if still pending (idempotency)
